CREATE TABLE FLIGHT_UPGRADES (
    UPGRADE_ID          NUMBER(10)       NOT NULL,
    RESERVATION_ID      NUMBER(10)       NOT NULL,
    PASSENGER_ID        NUMBER(10)       NOT NULL,
    FROM_CLASS          VARCHAR2(20)     NOT NULL,
    TO_CLASS            VARCHAR2(20)     NOT NULL,
    UPGRADE_TYPE        VARCHAR2(20)     NOT NULL,
    REQUEST_DATE        VARCHAR2(10)     NOT NULL,
    DECISION_DATE       VARCHAR2(10),
    UPGRADE_DATE        VARCHAR2(10),
    MILES_USED          NUMBER(10)       DEFAULT 0,
    AMOUNT_PAID         NUMBER(10,2)     DEFAULT 0,
    STATUS              VARCHAR2(15)     NOT NULL,
    REQUEST_CHANNEL     VARCHAR2(20)     NOT NULL,
    REJECTION_REASON    VARCHAR2(30),
    CONSTRAINT PK_FLIGHT_UPGRADES PRIMARY KEY (UPGRADE_ID)
);

